#include <stdio.h>
#include <string.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_system.h"
#include "esp_wifi.h"
#include "esp_http_client.h"

#define FIRMWARE_URL_MAX_LENGTH 256
#define FIRMWARE_FILE_NAME "firmware.bin"

char firmware_url[FIRMWARE_URL_MAX_LENGTH];

void http_download(const char *url, const char *filename) {
    esp_http_client_config_t config = {
        .url = url,
        .method = HTTP_METHOD_GET,
        .timeout_ms = 10000
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        printf("Failed to initialize HTTP client\n");
        return;
    }

    int status_code = esp_http_client_perform(client);
    if (status_code != ESP_OK) {
        printf("HTTP GET request failed: %d\n", status_code);
        return;
    }

    size_t content_length = esp_http_client_get_content_length(client);
    if (content_length == 0) {
        printf("No firmware data received from server\n");
        return;
    }

    char *firmware_data = malloc(content_length + 1);
    if (firmware_data == NULL) {
        printf("Failed to allocate memory for firmware data\n");
        return;
    }

    esp_http_client_read(client, firmware_data, content_length);
    firmware_data[content_length] = '\0';

    // Save firmware data to flash
    FILE *fp = fopen(filename, "wb");
    if (fp == NULL) {
        printf("Failed to open file for writing\n");
        free(firmware_data);
        return;
    }

    fwrite(firmware_data, 1, content_length, fp);
    fclose(fp);

    free(firmware_data);
}

void download_and_reboot() {
    http_download(firmware_url, FIRMWARE_FILE_NAME);
    esp_restart();
}

void app_main() {
    // Get firmware URL from device management server
    printf("Enter firmware update URL: ");
    fgets(firmware_url, FIRMWARE_URL_MAX_LENGTH, stdin);

    // Remove newline character from the end of the string
    firmware_url[strcspn(firmware_url, "\n")] = 0;

    download_and_reboot();
}